SELECT interest_score
FROM user_topics
WHERE user_id = 0 AND topic_id = 1 AND interest_date = '2023-01-31 20:00';

SELECT AVG(interest_score) AS average_interest_score
FROM user_topics
WHERE user_id = 0 AND interest_date = '2023-01-31 20:05';

SELECT MAX(engagement_score) AS max_engagement_score
FROM engagements
WHERE engagement_type = 'comment' AND engagement_date >= '2023-01-31 20:00';
